      p_status         => 'PUBLISHED',
      p_comments       => NULL);      
  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'getPickSearchRecords',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'getPickSearchRecords',
      p_method         => 'GET',
      p_source_type    => 'json/collection',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'WITH p AS (
    SELECT
        :p_work_order_number AS work_order_number,
        :p_work_order_from   AS work_order_from,
        :p_work_order_to     AS work_order_to,
        :p_item         AS item,
        :p_batch        AS batch,
        :p_scan_station AS scan_station,
        TO_DATE(NULLIF(TRIM(:p_start_date), ''''), ''YYYY-MM-DD'') AS start_date,
        TO_DATE(NULLIF(TRIM(:p_end_date),   ''''), ''YYYY-MM-DD'') AS end_date,
        :p_pick_slip_from AS pick_slip_from,
        :p_pick_slip_to   AS pick_slip_to,
        :p_slot_from AS slot_from,
        :p_slot_to   AS slot_to,
        TO_DATE(NULLIF(TRIM(:p_slot_scan_from), ''''), ''YYYY-MM-DD'') AS slot_scan_from_date,
        TO_DATE(NULLIF(TRIM(:p_slot_scan_to),   ''''), ''YYYY-MM-DD'') AS slot_scan_to_date,
        :p_warehouse_code_list AS warehouse_code_list,
        :p_source_si_list      AS source_si_list,
        :p_source_locator_list AS source_locator_list,
        :p_pick_status_list    AS pick_status_list,
        :p_short_pick_list     AS short_pick_list,
        :p_sub_batch_list      AS sub_batch_list,
        :p_slot_status_list    AS slot_status_list
    FROM dual
)
SELECT /*+ NO_PARALLEL */
    t.work_order_id,
    t.organization_id,
    t.batch,
    t.move_order_line_id,
    t.work_order_number,
    t.pick_slip_number,
    TO_CHAR(TRUNC(CAST(t.pick_slip_due_date AS DATE)), ''YYYY-MM-DD HH24:MI:SS'') AS pick_slip_due_date,
    TO_CHAR(CAST(t.transaction_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS transaction_date,
    TO_CHAR(CAST(t.last_update_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS last_update_date,
    TO_CHAR(CAST(t.component_scan_time_stamp AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS component_scan_time_stamp,
    TO_CHAR(CAST(t.slot_assignment_time_stamp AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS slot_assignment_time_stamp,
    TO_CHAR(CAST(t.final_bin_drop_time_stamp AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS final_bin_drop_time_stamp,
    t.picking_line_number,
    t.item,
    t.requested_quantity,
    t.picked_quantity,
    t.item_description,
    t.uom,
    t.quantity_exception,
    t.source_si,
    t.source_locator,
    t.destination_si,
    t.destination_locator,
    t.picked_by,
    t.last_updated_by,
    t.pick_slip_type,
    t.secondary_uom,
    t.pick_slip_status,
    t.demand_document_type,
    t.sub_batch,
    t.slot_assigned,
    t.slot_number,
    t.scanned_bin_number,
    t.slot_status,
    t.shortage_short_pick,
    t.pick_status,
    t.scan_station
FROM termfg_workorder_pick_stg t
CROSS JOIN p
WHERE 1 = 1
    AND (
            (p.work_order_number IS NOT NULL AND t.work_order_number = p.work_order_number)
        OR (
                p.work_order_number IS NULL
            AND (p.work_order_from IS NULL OR t.work_order_number >= p.work_order_from)
            AND (p.work_order_to IS NULL OR t.work_order_number <= p.work_order_to)
        )
    )
    AND (p.item IS NULL OR t.item = p.item)
    AND (p.batch IS NULL OR t.batch = p.batch)
    /* CSV scan stations: ''a,b,c'' or ''a'' — match t.scan_station to any token */
    AND (
        NULLIF(TRIM(p.scan_station), '''') IS NULL
        OR EXISTS (
            SELECT 1
            FROM (
                SELECT TRIM(REGEXP_SUBSTR(p.scan_station, ''[^,]+'', 1, LEVEL)) AS val
                FROM dual
                CONNECT BY REGEXP_SUBSTR(p.scan_station, ''[^,]+'', 1, LEVEL) IS NOT NULL
            ) z
            WHERE TRIM(z.val) = TRIM(t.scan_station)
        )
    )
    AND (p.start_date IS NULL OR CAST(t.pick_slip_due_date AS DATE) >= p.start_date)
    AND (p.end_date IS NULL OR CAST(t.pick_slip_due_date AS DATE) < p.end_date + 1)
    AND (p.slot_scan_from_date IS NULL OR CAST(t.final_bin_drop_time_stamp AS DATE) >= p.slot_scan_from_date)
    AND (p.slot_scan_to_date IS NULL OR CAST(t.final_bin_drop_time_stamp AS DATE) < p.slot_scan_to_date + 1)
    AND (p.pick_slip_from IS NULL OR t.pick_slip_number >= p.pick_slip_from)
    AND (p.pick_slip_to IS NULL OR t.pick_slip_number <= p.pick_slip_to)
    AND (p.slot_from IS NULL OR t.slot_number >= p.slot_from)
    AND (p.slot_to IS NULL OR t.slot_number <= p.slot_to)
    AND (
        NULLIF(TRIM(p.warehouse_code_list), '''') IS NULL
        OR EXISTS (
            SELECT 1
            FROM (
                SELECT TRIM(REGEXP_SUBSTR(p.warehouse_code_list, ''[^,]+'', 1, LEVEL)) AS val
                FROM dual
                CONNECT BY REGEXP_SUBSTR(p.warehouse_code_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
            ) w
            WHERE w.val = t.warehouse_code
        )
    )
    AND (
        NULLIF(TRIM(p.source_si_list), '''') IS NULL
        OR EXISTS (
            SELECT 1
            FROM (
                SELECT TRIM(REGEXP_SUBSTR(p.source_si_list, ''[^,]+'', 1, LEVEL)) AS val
                FROM dual
                CONNECT BY REGEXP_SUBSTR(p.source_si_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
            ) s
            WHERE s.val = t.source_si
        )
    )
    AND (
        NULLIF(TRIM(p.source_locator_list), '''') IS NULL
        OR EXISTS (
            SELECT 1
            FROM (
                SELECT TRIM(REGEXP_SUBSTR(p.source_locator_list, ''[^,]+'', 1, LEVEL)) AS val
                FROM dual
                CONNECT BY REGEXP_SUBSTR(p.source_locator_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
            ) l
            WHERE l.val = t.source_locator
        )
    )
    AND (
        NULLIF(TRIM(p.pick_status_list), '''') IS NULL
        OR EXISTS (
            SELECT 1
            FROM (
                SELECT TRIM(REGEXP_SUBSTR(p.pick_status_list, ''[^,]+'', 1, LEVEL)) AS val
                FROM dual
                CONNECT BY REGEXP_SUBSTR(p.pick_status_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
            ) ps
            WHERE ps.val = t.pick_status
        )
    )
    AND (
            NULLIF(TRIM(p.short_pick_list), '''') IS NULL
        OR (
                UPPER(TRIM(p.short_pick_list)) = ''YES''
            AND t.shortage_short_pick = ''Y''
            )
        OR (
                UPPER(TRIM(p.short_pick_list)) = ''NO''
            AND (t.shortage_short_pick IS NULL OR t.shortage_short_pick = ''N'')
            )
    )
    AND (
        NULLIF(TRIM(p.sub_batch_list), '''') IS NULL
        OR EXISTS (
            SELECT 1
            FROM (
                SELECT TRIM(REGEXP_SUBSTR(p.sub_batch_list, ''[^,]+'', 1, LEVEL)) AS val
                FROM dual
                CONNECT BY REGEXP_SUBSTR(p.sub_batch_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
            ) sb
            WHERE sb.val = t.sub_batch
        )
    )
    AND (
        NULLIF(TRIM(p.slot_status_list), '''') IS NULL
        OR EXISTS (
            SELECT 1
            FROM (
                SELECT TRIM(REGEXP_SUBSTR(p.slot_status_list, ''[^,]+'', 1, LEVEL)) AS val
                FROM dual
                CONNECT BY REGEXP_SUBSTR(p.slot_status_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
            ) ss
            WHERE ss.val = t.slot_status
        )
    )
    AND (
           p.work_order_number IS NOT NULL
        OR p.work_order_from IS NOT NULL
        OR p.work_order_to IS NOT NULL
        OR p.item IS NOT NULL
        OR p.batch IS NOT NULL
        OR NULLIF(TRIM(p.scan_station), '''') IS NOT NULL
        OR p.start_date IS NOT NULL
        OR p.end_date IS NOT NULL
        OR p.pick_slip_from IS NOT NULL
        OR p.pick_slip_to IS NOT NULL
        OR p.slot_from IS NOT NULL
        OR p.slot_to IS NOT NULL
        OR p.slot_scan_from_date IS NOT NULL
        OR p.slot_scan_to_date IS NOT NULL
        OR NULLIF(TRIM(p.warehouse_code_list), '''') IS NOT NULL
        OR NULLIF(TRIM(p.source_si_list), '''') IS NOT NULL
        OR NULLIF(TRIM(p.source_locator_list), '''') IS NOT NULL
        OR NULLIF(TRIM(p.pick_status_list), '''') IS NOT NULL
        OR NULLIF(TRIM(p.short_pick_list), '''') IS NOT NULL
        OR NULLIF(TRIM(p.sub_batch_list), '''') IS NOT NULL
        OR NULLIF(TRIM(p.slot_status_list), '''') IS NOT NULL
    )
ORDER BY t.work_order_number ASC'
      );
  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'WODeconsolidation',
