  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'getScanSlotNumberDetails',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'getScanSlotNumberDetails',
      p_method         => 'GET',
      p_source_type    => 'json/collection',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'SELECT slot_number, count_of_pick_slips
FROM (
    -- If the WO already has a slot, return that (pick the lowest if multiple)
    SELECT t.slot_number, t.count_of_pick_slips, 1 AS priority
    FROM   termfg_workorder_slot_scan_stg t
    WHERE  t.work_order = :p_wo

    UNION ALL

    -- Otherwise, return the lowest AVAILABLE (non-engaged) slot
    SELECT t2.slot_number, t2.count_of_pick_slips, 2 AS priority
    FROM   termfg_workorder_slot_scan_stg t2
    WHERE  NOT EXISTS (
              SELECT 1
              FROM   termfg_workorder_slot_scan_stg x
              WHERE  x.work_order = :p_wo
           )
      AND  t2.slot_status <> ''Engaged''          -- <-- replace with your "not engaged" rule/value(s)
) q
ORDER BY q.priority, q.slot_number
FETCH FIRST 1 ROW ONLY'
      );
