  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'getSearchSummaryRecords',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'getSearchSummaryRecords',
      p_method         => 'GET',
      p_source_type    => 'json/collection',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'WITH params AS (
    SELECT
        CASE
            WHEN NULLIF(TRIM(:p_start_date), '''') IS NULL THEN NULL
            ELSE TO_DATE(SUBSTR(:p_start_date, 1, 10), ''YYYY-MM-DD'')
        END AS p_start_dt,
        CASE
            WHEN NULLIF(TRIM(:p_completion_date), '''') IS NULL THEN NULL
            ELSE TO_DATE(SUBSTR(:p_completion_date, 1, 10), ''YYYY-MM-DD'')
        END AS p_comp_dt
    FROM dual
),
base AS (
    SELECT /*+ NO_PARALLEL(wo) */
        wo.work_order_id,
        wo.organization_id,
        wo.work_order_number,
        wo.item,
        wo.item_description,
        wo.quantity,
        wo.uom,
        wo.status,
        TO_CHAR(CAST(wo.released_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS released_date,
        wo.materials_available,
        wo.remaining_quantity,
        wo.remaining_quantity_uom,
        wo.completed_quantity,
        wo.completed_quantity_uom,
        wo.scrapped_quantity,
        wo.scrapped_quantity_uom,
        TO_CHAR(CAST(wo.actual_completion_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS actual_completion_date,
        TO_CHAR(CAST(wo.closed_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS closed_date,
        TO_CHAR(CAST(wo.cancelled_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS cancelled_date,
        wo.cancelled_reason,
        TO_CHAR(CAST(wo.start_date AS DATE), ''YYYY-MM-DD'') AS start_date,
        wo.start_past_due,
        TO_CHAR(CAST(wo.completion_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS completion_date,
        wo.comp_past_due,
        wo.wo_type,
        wo.wo_subtype,
        wo.work_definition,
        wo.version,
        TO_CHAR(CAST(wo.version_date AS DATE), ''YYYY-MM-DD HH24:MI:SS'') AS version_date,
        wo.serial_tracked_production,
        wo.completion_si,
        wo.completion_locator,
        wo.batch_number,
        TO_CHAR(CAST(wo.batch_creation_time AS TIMESTAMP), ''YYYY-MM-DD HH24:MI:SS'') AS batch_creation_time,
        wo.sub_batch_number,
        TO_CHAR(CAST(wo.sub_batch_number_creation_time AS TIMESTAMP), ''YYYY-MM-DD HH24:MI:SS'') AS sub_batch_number_creation_time,
        wo.status_of_deconsolidation,
        wo.warehouse_code,
        wo.substitutes,
        wo.progress,
        wo.source_system_type,
        wo.source_system,
        wo.source_header_reference,
        wo.source_line_reference,
        wo.document_number,
        wo.customer,
        wo.nettable_quantity,
        wo.assignment_priority,
        wo.work_order_priority,
        wo.wo_exception,
        wo.work_center,
        wo.work_area,
        wo.number_of_lines,
        MAX(wo.batch_number) OVER () AS max_batch_number,
        wo.scan_station
    FROM termfg_workorder_summary_stg wo
    CROSS JOIN params p
    WHERE 1 = 1
        AND ( :p_wo_from IS NULL OR wo.work_order_number >= :p_wo_from )
        AND ( :p_wo_to IS NULL OR wo.work_order_number <= :p_wo_to )
        AND ( p.p_start_dt IS NULL OR CAST(wo.start_date AS DATE) >= p.p_start_dt )
        AND ( p.p_comp_dt IS NULL OR CAST(wo.completion_date AS DATE) < p.p_comp_dt + 1 )
        AND ( :p_wo_type IS NULL OR wo.wo_type = :p_wo_type )
        AND ( :p_wo_subtype IS NULL OR wo.wo_subtype = :p_wo_subtype )
        AND ( :p_materials_available IS NULL OR wo.materials_available = :p_materials_available )
        AND ( :p_item IS NULL OR wo.item = :p_item )
        AND ( :p_work_definition IS NULL OR wo.work_definition = :p_work_definition )
        AND ( :p_status_of_deconsolidation IS NULL OR wo.status_of_deconsolidation = :p_status_of_deconsolidation )
        AND (
                :p_shortage_pick IS NULL
            OR NULLIF(TRIM(:p_shortage_pick), '''') IS NULL
            OR (
                    UPPER(TRIM(:p_shortage_pick)) = ''YES''
                AND NVL(wo.remaining_quantity, 0) <> 0
                )
            OR (
                    UPPER(TRIM(:p_shortage_pick)) = ''NO''
                AND NVL(wo.remaining_quantity, 0) = 0
                )
        )
        AND (
             NULLIF(TRIM(:p_work_order_priority), '''') IS NULL
          OR (
                 INSTR(TRIM(:p_work_order_priority), ''%'') > 0
             AND CAST(wo.work_order_priority AS VARCHAR2(4000)) LIKE TRIM(:p_work_order_priority)
             )
          OR (
                 INSTR(TRIM(:p_work_order_priority), ''%'') = 0
             AND CAST(wo.work_order_priority AS VARCHAR2(4000)) = TRIM(:p_work_order_priority)
             )
        )
        AND (
             NULLIF(TRIM(:p_assignment_priority), '''') IS NULL
          OR (
                 INSTR(TRIM(:p_assignment_priority), ''%'') > 0
             AND CAST(wo.assignment_priority AS VARCHAR2(4000)) LIKE TRIM(:p_assignment_priority)
             )
          OR (
                 INSTR(TRIM(:p_assignment_priority), ''%'') = 0
             AND CAST(wo.assignment_priority AS VARCHAR2(4000)) = TRIM(:p_assignment_priority)
             )
        )
        AND (
             NULLIF(TRIM(:p_work_center), '''') IS NULL
          OR (
                 INSTR(TRIM(:p_work_center), ''%'') > 0
             AND CAST(wo.work_center AS VARCHAR2(4000)) LIKE TRIM(:p_work_center)
             )
          OR (
                 INSTR(TRIM(:p_work_center), ''%'') = 0
             AND CAST(wo.work_center AS VARCHAR2(4000)) = TRIM(:p_work_center)
             )
        )
        AND (
             NULLIF(TRIM(:p_work_area), '''') IS NULL
          OR (
                 INSTR(TRIM(:p_work_area), ''%'') > 0
             AND CAST(wo.work_area AS VARCHAR2(4000)) LIKE TRIM(:p_work_area)
             )
          OR (
                 INSTR(TRIM(:p_work_area), ''%'') = 0
             AND CAST(wo.work_area AS VARCHAR2(4000)) = TRIM(:p_work_area)
             )
        )
        AND (
            NULLIF(TRIM(:p_status_list), '''') IS NULL
            OR EXISTS (
                SELECT 1
                FROM (
                    SELECT TRIM(REGEXP_SUBSTR(:p_status_list, ''[^,]+'', 1, LEVEL)) AS val
                    FROM dual
                    CONNECT BY REGEXP_SUBSTR(:p_status_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
                ) s
                WHERE s.val = wo.status
            )
        )
        AND (
            NULLIF(TRIM(:p_wo_exception_list), '''') IS NULL
            OR EXISTS (
                SELECT 1
                FROM (
                    SELECT TRIM(REGEXP_SUBSTR(:p_wo_exception_list, ''[^,]+'', 1, LEVEL)) AS val
                    FROM dual
                    CONNECT BY REGEXP_SUBSTR(:p_wo_exception_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
                ) x
                WHERE x.val = wo.wo_exception
            )
        )
        AND (
            NULLIF(TRIM(:p_warehouse_code_list), '''') IS NULL
            OR EXISTS (
                SELECT 1
                FROM (
                    SELECT TRIM(REGEXP_SUBSTR(:p_warehouse_code_list, ''[^,]+'', 1, LEVEL)) AS val
                    FROM dual
                    CONNECT BY REGEXP_SUBSTR(:p_warehouse_code_list, ''[^,]+'', 1, LEVEL) IS NOT NULL
                ) w
                WHERE w.val = wo.warehouse_code
            )
        )
        /* CSV scan stations: e.g. ''a,b,c'' or ''a'' — match wo.scan_station to any token */
        AND (
            NULLIF(TRIM(:p_scan_station), '''') IS NULL
            OR EXISTS (
                SELECT 1
                FROM (
                    SELECT TRIM(REGEXP_SUBSTR(:p_scan_station, ''[^,]+'', 1, LEVEL)) AS val
                    FROM dual
                    CONNECT BY REGEXP_SUBSTR(:p_scan_station, ''[^,]+'', 1, LEVEL) IS NOT NULL
                ) z
                WHERE TRIM(z.val) = TRIM(wo.scan_station)
            )
        )
        AND (
               :p_wo_from IS NOT NULL
            OR :p_wo_to IS NOT NULL
            OR p.p_start_dt IS NOT NULL
            OR p.p_comp_dt IS NOT NULL
            OR :p_wo_type IS NOT NULL
            OR :p_wo_subtype IS NOT NULL
            OR NULLIF(TRIM(:p_work_order_priority), '''') IS NOT NULL
            OR NULLIF(TRIM(:p_assignment_priority), '''') IS NOT NULL
            OR NULLIF(TRIM(:p_work_center), '''') IS NOT NULL
            OR NULLIF(TRIM(:p_work_area), '''') IS NOT NULL
            OR :p_materials_available IS NOT NULL
            OR :p_item IS NOT NULL
            OR NULLIF(TRIM(:p_status_list), '''') IS NOT NULL
            OR NULLIF(TRIM(:p_wo_exception_list), '''') IS NOT NULL
            OR NULLIF(TRIM(:p_warehouse_code_list), '''') IS NOT NULL
            OR :p_work_definition IS NOT NULL
            OR :p_batch_created IS NOT NULL
            OR :p_status_of_deconsolidation IS NOT NULL
            OR NULLIF(TRIM(:p_shortage_pick), '''') IS NOT NULL
            OR NULLIF(TRIM(:p_scan_station), '''') IS NOT NULL
        )
)
SELECT *
FROM base
WHERE
    (
        :p_batch_created IS NULL
        OR UPPER(:p_batch_created) <> ''YES''
        OR base.batch_number = base.max_batch_number
    )
ORDER BY base.work_order_number ASC'
      );
