  ORDS.DEFINE_HANDLER(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'getWOKittReportCount',
      p_method         => 'GET',
      p_source_type    => 'json/collection',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'WITH input_list AS (
  SELECT DISTINCT
         jt.work_order_number,
         jt.warehouse_code
  FROM JSON_TABLE(
         :body,
         ''$[*]''
         COLUMNS (
           work_order_number VARCHAR2(100) PATH ''$.work_order_number'',
           warehouse_code    VARCHAR2(100) PATH ''$.warehouse_code''
         )
       ) jt
)
SELECT
  i.work_order_number,
  i.warehouse_code,
  COALESCE(MIN(CASE WHEN t.slot_status = ''Bin Dropped'' THEN 1 ELSE 0 END), 0) AS count
FROM input_list i
LEFT JOIN termfg_workorder_pick_stg t
  ON t.work_order_number = i.work_order_number
 AND t.warehouse_code             = i.warehouse_code
GROUP BY i.work_order_number, i.warehouse_code
ORDER BY i.work_order_number, i.warehouse_code;


