      p_comments       => NULL,
      p_source         => 
'WITH input_list AS (
  SELECT DISTINCT
         jt.work_order_number,
         jt.warehouse_code
  FROM JSON_TABLE(
         :body,
         ''$[*]''
         COLUMNS (
           work_order_number VARCHAR2(100) PATH ''$.work_order_number'',
           warehouse_code    VARCHAR2(100) PATH ''$.warehouse_code''
         )
       ) jt
)
SELECT
  i.work_order_number,
  i.warehouse_code,
  COALESCE(
    SUM(
      CASE
        WHEN (t.REMAINING_QUANTITY != 0) OR (UPPER(t.MATERIALS_AVAILABLE) = ''PARTIAL'') THEN 1
        ELSE 0
      END
    ),
    0
  ) AS count
FROM input_list i
LEFT JOIN termfg_workorder_summary_stg t
  ON t.work_order_number = i.work_order_number
 AND t.warehouse_code    = i.warehouse_code
GROUP BY i.work_order_number, i.warehouse_code
ORDER BY i.work_order_number, i.warehouse_code'
      );
