      p_source         => 
'BEGIN
UPDATE termfg_workorder_summary_stg s
   SET s.kitt_report_id      = :p_reportId,
       s.last_updated_date   = SYSTIMESTAMP,
       s.last_updated_by     = :p_name
 WHERE s.work_order_number IN (
   SELECT TRIM(REGEXP_SUBSTR(:p_workOrder, ''[^,]+'', 1, LEVEL))
     FROM dual
   CONNECT BY REGEXP_SUBSTR(:p_workOrder, ''[^,]+'', 1, LEVEL) IS NOT NULL
 )
 AND s.warehouse_code = :p_warehouseCode ;

COMMIT;
END;'
      );
  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'WODeconsolidation',
