      p_pattern        => 'updatePrintLabelDetails',
      p_method         => 'GET',
      p_source_type    => 'plsql/block',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'BEGIN
    IF :check_label_type = ''Batch'' THEN
        UPDATE TERMFG_WORKORDER_SUMMARY_STG
        SET     LAST_UPDATED_BY = :p_updatedBy,
                LAST_UPDATED_DATE = SYSDATE,
                PRINT_LABEL_COMMENTS = :p_label_comments,
                PRINT_TYPE = :p_print_type,
                PROCESS_ID = :p_process_id
        WHERE  BATCH_NUMBER = :p_input;
    ELSIF :check_label_type = ''Sub-Batch'' THEN
        UPDATE TERMFG_WORKORDER_PICK_STG
        SET     LAST_UPDATED_BY = :p_updatedBy,
                LAST_UPDATED_DATE = SYSDATE,
                PRINT_LABEL_COMMENTS = :p_label_comments,
                PRINT_TYPE = :p_print_type,
                PROCESS_ID = :p_process_id
        WHERE  SUB_BATCH = :p_input;
    END IF;
    COMMIT;
END;'
      );
