  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'updateSummaryTableStatusOfDeconsolidation',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'WODeconsolidation',
      p_pattern        => 'updateSummaryTableStatusOfDeconsolidation',
      p_method         => 'GET',
      p_source_type    => 'plsql/block',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'DECLARE
    v_rows NUMBER;
BEGIN
    UPDATE termfg_workorder_summary_stg s
    SET
        status_of_deconsolidation = ''Done''
    WHERE
            s.scan_station IS NOT NULL
        AND EXISTS (
            SELECT 1
            FROM   termfg_workorder_pick_stg p
            WHERE  p.work_order_number = s.work_order_number
            AND    p.warehouse_code = s.warehouse_code
        )
        AND NOT EXISTS (
            SELECT 1
            FROM   termfg_workorder_pick_stg p2
            WHERE  p2.work_order_number = s.work_order_number
            AND    p2.warehouse_code = s.warehouse_code
            AND    (
                        p2.slot_status IS NULL
                    OR p2.slot_status <> ''Bin Dropped''
                )
        );
    v_rows := SQL%ROWCOUNT;
    --DBMS_OUTPUT.PUT_LINE(''Rows updated: '' || v_rows);
    COMMIT;
END;'
      );


  COMMIT; 
END;